import React, { useEffect, useState } from "react";
import axios from "axios";
import { Bar, Pie } from "react-chartjs-2";
import './AdminDashboard.css';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, Tooltip, Legend);

const AdminDashboard = () => {
  const [predictions, setPredictions] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get("http://localhost:5000/admin/dashboard");
        setPredictions(res.data.predictions || []);
      } catch (err) {
        console.error("Error fetching data:", err);
      }
    };
    fetchData();
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  const totalUsers = predictions.length;
  const salaries = predictions.map(p => p.salary).filter(s => s != null);
  const avgSalary = salaries.length ? (salaries.reduce((a, b) => a + b, 0) / salaries.length) : 0;
  const highestSalary = salaries.length ? Math.max(...salaries) : 0;
  const lowestSalary = salaries.length ? Math.min(...salaries) : 0;

  return (
    <div className="admin-container">
      {/* FIXED SIDEBAR */}
      <aside className="admin-sidebar">
        <div className="brand-area">
          <div className="admin-avatar">👤</div>
          <h3>Admin Panel</h3>
        </div>
        <nav className="nav-list">
          <div className="nav-item active">Dashboard</div>
          <div className="nav-item">Manage Users</div>
          <div className="nav-item">Reports</div>
          <div className="nav-item">Settings</div>
        </nav>
        <button className="btn-logout" onClick={handleLogout}>Logout</button>
      </aside>

      {/* MAIN CONTENT AREA */}
      <main className="admin-main">
        <header className="admin-header">
          <h2>Dashboard Overview</h2>
          <div className="header-tools">
            <span className="icon">🔔</span>
            <span className="icon">⚙️</span>
          </div>
        </header>

        <div className="admin-content">
          {/* STAT CARDS */}
          <section className="stats-row">
            <div className="stat-card color-1">
              <span>Avg. Salary</span>
              <h2>₹{avgSalary.toLocaleString()}</h2>
            </div>
            <div className="stat-card color-2">
              <span>Highest Salary</span>
              <h2>₹{highestSalary.toLocaleString()}</h2>
            </div>
            <div className="stat-card color-3">
              <span>Lowest Salary</span>
              <h2>₹{lowestSalary.toLocaleString()}</h2>
            </div>
            <div className="stat-card color-4">
              <span>Total Users</span>
              <h2>{totalUsers}</h2>
            </div>
          </section>

          {/* CHARTS */}
          <section className="charts-grid">
            <div className="chart-wrapper animate-up">
              <h4>Salary Distribution</h4>
              <div className="chart-inner">
                <Bar 
                  data={{
                    labels: ["<40k", "40-60k", "60-80k", "80-100k", ">100k"],
                    datasets: [{
                      label: 'Predictions',
                      data: [
                        predictions.filter(p => p.salary < 40000).length,
                        predictions.filter(p => p.salary >= 40000 && p.salary < 60000).length,
                        predictions.filter(p => p.salary >= 60000 && p.salary < 80000).length,
                        predictions.filter(p => p.salary >= 80000 && p.salary < 100000).length,
                        predictions.filter(p => p.salary >= 100000).length,
                      ],
                      backgroundColor: '#3b82f6',
                      borderRadius: 6
                    }]
                  }} 
                  options={{ maintainAspectRatio: false }}
                />
              </div>
            </div>
            <div className="chart-wrapper animate-up delay-1">
              <h4>Demographics</h4>
              <div className="chart-inner">
                <Pie 
                  data={{
                    labels: ["Experienced", "Entry", "Intermediate", "Post-Grad"],
                    datasets: [{
                      data: [
                        predictions.filter(p => p.experience === "Experienced").length || 1,
                        predictions.filter(p => p.experience === "Entry").length || 1,
                        predictions.filter(p => p.experience === "Intermediate").length || 1,
                        predictions.filter(p => p.experience === "Post-Graduate").length || 1
                      ],
                      backgroundColor: ["#6366f1", "#f59e0b", "#10b981", "#ef4444"]
                    }]
                  }}
                  options={{ maintainAspectRatio: false }}
                />
              </div>
            </div>
          </section>

          {/* TABLE */}
          <section className="table-wrapper animate-up delay-2">
            <h4>Recent Prediction Activity</h4>
            <table className="styled-table">
              <thead>
                <tr>
                  <th>Email</th>
                  <th>Role</th>
                  <th>Location</th>
                  <th>Result</th>
                </tr>
              </thead>
              <tbody>
                {predictions.slice(-5).reverse().map((p, i) => (
                  <tr key={i}>
                    <td>{p.email}</td>
                    <td>{p.role}</td>
                    <td>{p.location}</td>
                    <td className="salary-val">₹{p.salary?.toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </section>
        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
